// generar_214_orina_tiroides_estructurados.js
// CHIQUI Entre Señales — Examen de Orina y Perfil Tiroideo enriquecidos
//
// Qué hace (refactorización de 2 exámenes EXISTENTES, sin tipos nuevos
// ni SQL -- cada parámetro sigue guardándose como fila independiente):
//
// 🚽 Examen de orina → 3 secciones colapsables (cerradas por defecto):
//   - Examen físico: Color y Aspecto con listas de opciones, Olor,
//     Volumen (mL), Densidad USG con rango por especie.
//   - Examen químico: pH con rango por especie (perro 5.5-7.5, gato
//     6.0-7.5) y tira reactiva con listas (Negativo/Traza/1+...4+,
//     Urobilinógeno Normal/Elevado, Nitritos Negativo/Positivo).
//   - Sedimento urinario: listas para células, bacterias, levaduras,
//     cristales (estruvita, oxalato...), cilindros y moco.
//
// 🦋 Perfil tiroideo → 2 secciones colapsables:
//   - Hormonas tiroideas: T4 Total con rango por especie (perro
//     1.0-4.0, gato 0.8-4.7 µg/dL), T4 Libre, TSH Canina/Felina según
//     especie, T3 Total.
//   - Autoanticuerpos (SOLO PERROS): TgAA, Autoanticuerpos T3 y T4 con
//     Negativo/Positivo.
//
// Vista /vet: tabla del examen más reciente agrupada con subtítulos de
// sección; los resultados "Positivo" (nitritos, autoanticuerpos, etc.)
// se destacan en rojo y se suman al resumen de hallazgos junto a los
// valores fuera de rango. La comparación entre fechas también los
// resalta.
//
// Uso: arrastrar este archivo a la raíz del proyecto y correr:
//   node generar_214_orina_tiroides_estructurados.js

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: "components/ExamenesLab.tsx",
    base64: ""
  },
  {
    ruta: "components/ExamenesLabVet.tsx",
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs2.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('')
  console.log('Listo. 2 archivos escritos correctamente.')
  console.log('No hay SQL esta vez. Puedes hacer git add / commit / push directo.')
} else {
  console.error('')
  console.error('Terminó con ' + errores + ' error(es). NO hagas git push todavía.')
  process.exit(1)
}
